    snake_head_x += snake_direction;
    snake_head_y -= snake_direction == 0 ? 1 : 0;
    snake_head_x -= snake_direction == 1 ? 1 : 0;
    snake_head_y += snake_direction == 2 ? 1 : 0;
    snake_head_x += snake_direction == 3 ? 1 : 0;
