Here's a function in JavaScript that takes an array of 5 numbers as input and checks if any of the numbers is a valid prime number:

```javascript
function checkPrimeNumbers(numbers) {
  for (let i = 0; i < numbers.length; i++) {
    if (isPrime(numbers[i])) {
      console.log(numbers[i] + " is a valid prime number.");
    }
  }
}

function isPrime(num) {
  if (num <= 1) return false;
  if (num === 2) return true;
  if (num % 2 === 0) return false;
  let sqrtNum = Math.sqrt(num);
  for (let i = 3; i <= sqrtNum; i += 2) {
    if (num % i === 0) return false;
  }
  return true;
}

// Example usage:
checkPrimeNumbers([4, 6, 9, 11, 15]);
```

This code defines two functions. The `checkPrimeNumbers` function takes an array of 5 numbers as input and checks if any of the numbers is a valid prime number using the `isPrime` function. The `isPrime` function checks if a given number is a prime number.

